simple_types.code:
type Comparison_Type is
  (X,
  Pos,
  Comp,
  Super
  );

record_types.code:
type Adjective_Record is
   record
      Decl        : Decn_Record;
      Of_Case     : Case_Type := X;
      Number      : Number_Type := X;
      Gender      : Gender_Type := X;
      Comparison  : Comparison_Type := X;
   end record;

type Adverb_Record is
   record
      Comparison   : Comparison_Type := X;
   end record;

type Decn_Record is
   record
      Which        : Which_Type   := 0;
      Var          : Variant_Type := 0;
   end record;

type Ending_Record is
   record
      Size : Ending_Size_Type := 0;
      Suf  : Ending := (others => ' ');
   end record;

type Inflection_Record is
   record
      Qual   : Quality_Record := Null_Quality_Record;
      Key    : Stem_Key_Type  := 0;
      Ending : Ending_Record  := Null_Ending_Record;
      Age    : Age_Type       := X;
      Freq   : Frequency_Type := X;
   end record;

type Noun_Record is
   record
      Decl        : Decn_Record;
      Of_Case     : Case_Type    := X;
      Number      : Number_Type  := X;
      Gender      : Gender_Type  := X;
   end record;

type Numeral_Record is
   record
      Decl        : Decn_Record;
      Of_Case     : Case_Type := X;
      Number      : Number_Type := X;
      Gender      : Gender_Type := X;
      Sort        : Numeral_Sort_Type := X;
   end record;

type Preposition_Record is
   record
      Of_Case : Case_Type := X;
   end record;

type Pronoun_Record is
   record
      Decl        : Decn_Record;
      Of_Case     : Case_Type := X;
      Number      : Number_Type := X;
      Gender      : Gender_Type := X;
   end record;

type Propack_Record is
   record
      Decl        : Decn_Record;
      Of_Case     : Case_Type   := X;
      Number      : Number_Type := X;
      Gender      : Gender_Type := X;
   end record;

type Quality_Record (Pofs : Part_Of_Speech_Type := X) is
   record
      case Pofs is
         when N =>
            Noun : Noun_Record;
         when Pron =>
            Pron : Pronoun_Record;
         when Pack =>
            Pack : Propack_Record;
         when Adj =>
            Adj : Adjective_Record;
         when Num =>
            Num : Numeral_Record;
         when Adv =>
            Adv : Adverb_Record;
         when V =>
            Verb : Verb_Record;
         when Vpar =>
            Vpar : Vpar_Record;
         when Supine =>
            Supine : Supine_Record;
         when Prep =>
            Prep : Preposition_Record;
         when Conj =>
            Conj : Conjunction_Record;
         when Interj =>
            Interj : Interjection_Record;
         when Tackon =>
            Tackon : Tackon_Record;
         when Prefix =>
            Prefix : Prefix_Record;
         when Suffix =>
            Suffix : Suffix_Record;
         when X =>
            null;
      end case;
   end record;

type Supine_Record is
   record
      Con         : Decn_Record;
      Of_Case     : Case_Type := X;
      Number      : Number_Type := X;
      Gender      : Gender_Type := X;
   end record;

type Tense_Voice_Mood_Record is
   record
      Tense : Tense_Type := X;
      Voice : Voice_Type := X;
      Mood  : Mood_Type  := X;
   end record;

type Verb_Record is
   record
      Con         : Decn_Record;
      Tense_Voice_Mood  : Tense_Voice_Mood_Record;
      Person      : Person_Type := 0;
      Number      : Number_Type := X;
   end record;

type Vpar_Record is
   record
      Con         : Decn_Record;
      Of_Case     : Case_Type := X;
      Number      : Number_Type := X;
      Gender      : Gender_Type := X;
      Tense_Voice_Mood  : Tense_Voice_Mood_Record;
   end record;
